class PaymentSecurity {
  static String generateIdempotencyKey({
    required String orderId,
    required String userId,
    required int timestampMs,
  }) {
    final input = '$orderId:$userId:$timestampMs';
    return sha256.convert(utf8.encode(input)).toString();
  }

  static Map<String, String> secureHeaders({
    required PaymentConfig config,
    String? idempotencyKey,
    String? authToken,
  }) {
    return {
      HttpHeaders.contentTypeHeader: 'application/json',
      HttpHeaders.acceptHeader: 'application/json',
      'X-Api-Version': config.apiVersion,
      if (idempotencyKey != null) 'Idempotency-Key': idempotencyKey,
      if (authToken != null) HttpHeaders.authorizationHeader: 'Bearer $authToken',
      'X-Client-Platform': Platform.operatingSystem,
      'X-Client-Mode': config.environment.name,
    };
  }

  static void assertPciSafe({
    String? rawCardNumber,
    String? cvv,
    String? trackData,
  }) {
    if (rawCardNumber != null && rawCardNumber.isNotEmpty) {
      throw const PaymentException(
        'pci_violation',
        'Raw card data must not be handled in the client. Use tokenization only.',
      );
    }
    if (cvv != null && cvv.isNotEmpty) {
      throw const PaymentException(
        'pci_violation',
        'CVV must not be stored or transmitted through this client module.',
      );
    }
    if (trackData != null && trackData.isNotEmpty) {
      throw const PaymentException(
        'pci_violation',
        'Track data must not be handled in the client.',
      );
    }
  }
}

class PaymentLogger {
