  const PaymentLogger(this.enabled);

  void log(String message, [Map<String, dynamic>? data]) {
    if (!enabled) return;
    debugPrint('[Payment] $message ${data != null ? _redact(data) : ''}');
  }

  Map<String, dynamic> _redact(Map<String, dynamic> data) {
    final cloned = Map<String, dynamic>.from(data);
    const sensitiveKeys = {
      'clientSecret',
      'token',
      'paymentToken',
      'receipt',
      'authorization',
      'authToken',
      'cardNumber',
      'cvv',
      'pan',
    };
    cloned.updateAll((key, value) {
      if (sensitiveKeys.contains(key)) return '***REDACTED***';
      if (value is Map<String, dynamic>) return _redact(value);
      return value;
    });
    return cloned;
  }
}

class PaymentApiClient {
  final PaymentConfig config;
  final http.Client _httpClient;
  final PaymentLogger _logger;

  PaymentApiClient({
    required this.config,
    http.Client? httpClient,
  })  : _httpClient = httpClient ?? http.Client(),
        _logger = PaymentLogger(config.enableLogging);

  Future<Map<String, dynamic>> post(
    String path, {
    required Map<String, dynamic> body,
    String? authToken,
    String? idempotencyKey,
  }) async {
    final uri = config.backendBaseUrl.resolve(path);
    _logger.log('POST $uri', body);
    final response = await _httpClient
        .post(
          uri,
          headers: PaymentSecurity.secureHeaders(
            config: config,
            authToken: authToken,
            idempotencyKey: idempotencyKey,
          ),
          body: jsonEncode(body),
        )
        .timeout(config.networkTimeout);

    return _decodeResponse(response);
  }

  Future<Map<String, dynamic>> get(
    String path, {
    String? authToken,
  }) async {
    final uri = config.backendBaseUrl.resolve(path);
    _logger.log('GET $uri');
    final response = await _httpClient
        .get(
          uri,
          headers: PaymentSecurity.secureHeaders(
            config: config,
            authToken: authToken,
          ),
        )
        .timeout(config.networkTimeout);

    return _decodeResponse(response);
  }

  Map<String, dynamic> _decodeResponse(http.Response response) {
    final body = response.body.isEmpty
        ? <String, dynamic>{}
        : jsonDecode(response.body) as Map<String, dynamic>;
    _logger.log('RESPONSE ${response.statusCode}', body);
    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw PaymentException(
        body['code']?.toString() ?? 'http_${response.statusCode}',
        body['message']?.toString() ?? 'Payment API request failed',
      );
    }
    return body;
  }

  void dispose() {
    _httpClient.close();
  }
}

