class InAppPurchaseService {
  final InAppPurchase _iap = InAppPurchase.instance;
  final PaymentApiClient apiClient;
  final PaymentConfig config;
  final PaymentLogger _logger;

  StreamSubscription<List<PurchaseDetails>>? _purchaseSubscription;

  InAppPurchaseService({
    required this.apiClient,
    required this.config,
  }) : _logger = PaymentLogger(config.enableLogging);

  Future<bool> isAvailable() => _iap.isAvailable();

  Future<ProductDetailsResponse> queryProducts() {
    return _iap.queryProductDetails(config.iapProductIds);
  }

  Future<void> initialize({
    required Future<void> Function(PurchaseDetails purchase) onVerifiedPurchase,
    Future<void> Function(PurchaseDetails purchase)? onPendingPurchase,
    Future<void> Function(PurchaseDetails purchase, Object error)? onFailedPurchase,
  }) async {
    _purchaseSubscription?.cancel();
    _purchaseSubscription = _iap.purchaseStream.listen(
      (purchases) async {
        for (final purchase in purchases) {
          try {
            if (purchase.status == PurchaseStatus.pending) {
              if (onPendingPurchase != null) {
                await onPendingPurchase(purchase);
              }
              continue;
            }

            if (purchase.status == PurchaseStatus.error) {
              if (onFailedPurchase != null) {
                await onFailedPurchase(
                  purchase,
                  PaymentException(
                    purchase.error?.code ?? 'purchase_error',
                    purchase.error?.message ?? 'Unknown purchase error',
                  ),
                );
              }
              if (purchase.pendingCompletePurchase) {
                await _iap.completePurchase(purchase);
              }
              continue;
            }

            if (purchase.status == PurchaseStatus.purchased ||
                purchase.status == PurchaseStatus.restored) {
              await verifyAndAcknowledgePurchase(purchase);
              await onVerifiedPurchase(purchase);
            }

            if (purchase.pendingCompletePurchase) {
              await _iap.completePurchase(purchase);
            }
          } catch (e, st) {
            if (onFailedPurchase != null) {
              await onFailedPurchase(purchase, PaymentException('verification_failed', '$e', cause: e, stackTrace: st));
            }
          }
        }
      },
      onError: (error) {
        _logger.log('purchaseStreamError', {'error': error.toString()});
      },
      cancelOnError: false,
    );
  }

  Future<void> buy(InAppPurchaseRequest request) async {
    final response = await queryProducts();
    if (response.notFoundIDs.contains(request.productId)) {
      throw PaymentException(
        'product_not_found',
        'Product ${request.productId} not found in store configuration.',
      );
    }

    final product = response.productDetails.firstWhere(
      (p) => p.id == request.productId,
      orElse: () => throw PaymentException(
        'product_not_found',
        'Product ${request.productId} not available.',
      ),
    );

    final purchaseParam = PurchaseParam(
      productDetails: product,
      applicationUserName: request.applicationUserName,
    );

    if (request.consumable) {
      final ok = await _iap.buyConsumable(
        purchaseParam: purchaseParam,
        autoConsume: Platform.isAndroid,
      );
      if (!ok) {
        throw const PaymentException('purchase_start_failed', 'Unable to start consumable purchase.');
      }
    } else {
      final ok = await _iap.buyNonConsumable(purchaseParam: purchaseParam);
      if (!ok) {
        throw const PaymentException('purchase_start_failed', 'Unable to start non-consumable purchase.');
      }
    }
  }

  Future<PaymentResult> verifyAndAcknowledgePurchase(PurchaseDetails purchase) async {
    final payload = {
      'source': 'in_app_purchase',
      'platform': Platform.operatingSystem,
      'productId': purchase.productID,
      'purchaseId': purchase.purchaseID,
      'transactionDate': purchase.transactionDate,
      'verificationData': {
        'localVerificationData': purchase.verificationData.localVerificationData,
        'serverVerificationData': purchase.verificationData.serverVerificationData,
        'source': purchase.verificationData.source,
      },
      'status': purchase.status.name,
    };

    final json = await apiClient.post(
      '/payments/iap/verify',
      body: payload,
      idempotencyKey: purchase.purchaseID ?? sha256.convert(utf8.encode(payload.toString())).toString(),
    );

    return PaymentResult.fromJson(json);
  }

  Future<void> restorePurchases() async {
    await _iap.restorePurchases();
  }

  Future<void> dispose() async {
    await _purchaseSubscription?.cancel();
  }
}

class WalletPaymentService {
  final PaymentApiClient apiClient;
  final PaymentConfig config;
  final WalletBridge _walletBridge;
  final PaymentLogger _logger;

  WalletPaymentService({
    required this.apiClient,
    required this.config,
    WalletBridge? walletBridge,
  })  : _walletBridge = walletBridge ?? WalletBridge(),
        _logger = PaymentLogger(config.enableLogging);

  Future<bool> isAvailable(PlatformWalletType type) {
    return _walletBridge.isWalletAvailable(type);
  }

  Future<PaymentResult> pay(WalletPaymentRequest request, {String? authToken}) async {
    final available = await isAvailable(request.walletType);
    if (!available) {
      throw PaymentException(
        'wallet_not_available',
        '${request.walletType.name} is not available on this device.',
      );
    }

    final walletTokenResponse = await _walletBridge.requestPaymentToken(request);
    final paymentToken = walletTokenResponse['paymentToken']?.toString();
    if (paymentToken == null || paymentToken.isEmpty) {
      throw const PaymentException('wallet_token_missing', 'Wallet tokenization failed.');
    }

    final body = {
      ...request.toJson(),
      'paymentToken': paymentToken,
      'gateway': walletTokenResponse['gateway'],
      'network': walletTokenResponse['network'],
      'transactionIdentifier': walletTokenResponse['transactionIdentifier'],
    };

    final json = await apiClient.post(
      '/payments/wallet/charge',
      body: body,
      authToken: authToken,
      idempotencyKey: sha256.convert(utf8.encode('${request.orderId}:${request.walletType.name}:${request.amount.minorUnits}')).toString(),
    );

    _logger.log('walletPaymentProcessed', {'orderId': request.orderId, 'status': json['status']});
    return PaymentResult.fromJson(json);
  }
}

class GatewayPaymentService {
  final PaymentApiClient apiClient;
  final PaymentConfig config;
  final PaymentLogger _logger;

  GatewayPaymentService({
    required this.apiClient,
    required this.config,
  }) : _logger = PaymentLogger(config.enableLogging);

  Future<PaymentIntentResponse> createPaymentIntent(
    PaymentRequest request, {
    String? authToken,
  }) async {
    PaymentSecurity.assertPciSafe();
    final json = await apiClient.post(
      '/payments/intents',
      body: request.toJson(),
      authToken: authToken,
      idempotencyKey: request.idempotencyKey,
    );
    return PaymentIntentResponse.fromJson(json);
  }

  Future<PaymentResult> confirmTokenizedPayment({
    required String paymentIntentId,
    required String paymentMethodToken,
    required PaymentMethodType methodType,
    String? authToken,
    Map<String, dynamic> metadata = const {},
  }) async {
    PaymentSecurity.assertPciSafe();
    final json = await apiClient.post(
      '/payments/intents/$paymentIntentId/confirm',
      body: {
        'paymentMethodToken': paymentMethodToken,
        'methodType': methodType.name,
        'metadata': metadata,
      },
      authToken: authToken,
      idempotencyKey: sha256.convert(utf8.encode('$paymentIntentId:$paymentMethodToken')).toString(),
    );
    _logger.log('paymentConfirmed', {'paymentIntentId': paymentIntentId, 'status': json['status']});
    return PaymentResult.fromJson(json);
  }

  Future<PaymentResult> capturePayment({
    required String paymentIntentId,
    String? authToken,
    int? amountToCaptureMinorUnits,
  }) async {
    final json = await apiClient.post(
      '/payments/intents/$paymentIntentId/capture',
      body: {
        if (amountToCaptureMinorUnits != null) 'amountToCaptureMinorUnits': amountToCaptureMinorUnits,
      },
      authToken: authToken,
      idempotencyKey: sha256.convert(utf8.encode('capture:$paymentIntentId:${amountToCaptureMinorUnits ?? ''}')).toString(),
    );
    return PaymentResult.fromJson(json);
  }

  Future<PaymentResult> refundPayment({
    required String transactionId,
    required PaymentAmount amount,
    String? reason,
    String? authToken,
  }) async {
    final json = await apiClient.post(
      '/payments/refunds',
      body: {
        'transactionId': transactionId,
        'amount': amount.toJson(),
        'reason': reason,
      }..removeWhere((key, value) => value == null),
      authToken: authToken,
      idempotencyKey: sha256.convert(utf8.encode('refund:$transactionId:${amount.minorUnits}:${amount.currency}')).toString(),
    );
    return PaymentResult.fromJson(json);
  }

  Future<PaymentResult> getPaymentStatus(
    String paymentIntentId, {
    String? authToken,
  }) async {
    final json = await apiClient.get(
      '/payments/intents/$paymentIntentId',
      authToken: authToken,
    );
    return PaymentResult.fromJson(json);
  }
}

class PaymentModule {
  final PaymentConfig config;
  late final PaymentApiClient apiClient;
  late final GatewayPaymentService gateway;
  late final WalletPaymentService wallet;
  late final InAppPurchaseService iap;

  PaymentModule._(this.config) {
    apiClient = PaymentApiClient(config: config);
    gateway = GatewayPaymentService(apiClient: apiClient, config: config);
    wallet = WalletPaymentService(apiClient: apiClient, config: config);
    iap = InAppPurchaseService(apiClient: apiClient, config: config);
  }

  static PaymentModule initialize(PaymentConfig config) {
    return PaymentModule._(config);
  }

  Future<void> dispose() async {
    await iap.dispose();
    apiClient.dispose();
  }
}

PaymentStatus _paymentStatusFromString(String? value) {
  switch (value) {
    case 'pending':
      return PaymentStatus.pending;
    case 'requiresAction':
      return PaymentStatus.requiresAction;
    case 'authorized':
      return PaymentStatus.authorized;
    case 'captured':
      return PaymentStatus.captured;
    case 'succeeded':
      return PaymentStatus.succeeded;
    case 'failed':
      return PaymentStatus.failed;
    case 'cancelled':
      return PaymentStatus.cancelled;
    case 'refunded':
      return PaymentStatus.refunded;
    default:
      return PaymentStatus.pending;
  }
}